// Some portions generated by Claude
package org.eclipse.rdf4j.query.algebra.equivalence.internal;

import java.util.ArrayList;
import java.util.List;

import org.eclipse.rdf4j.model.Statement;
import org.eclipse.rdf4j.model.ValueFactory;
import org.eclipse.rdf4j.query.algebra.equivalence.ContextMode;
import org.eclipse.rdf4j.query.algebra.equivalence.EvaluationCase;
import org.eclipse.rdf4j.query.impl.MapBindingSet;
import org.eclipse.rdf4j.query.impl.SimpleDataset;

/**
 * Explicit evaluation cases handed to every fuzz profile, generalizing the matrix idea from
 * {@link RuntimeEquivalenceDifferentialTest}: empty data, joinable fan-out data over the fuzz vocabulary,
 * duplicate-producing merged default graphs, sparse data, and (under ALL_BINDINGS) an incoming binding.
 */
final class FuzzEvaluationMatrix {
	private static final ValueFactory VF = FuzzVocabulary.VF;

	private FuzzEvaluationMatrix() {
	}

	static List<EvaluationCase> cases(ContextMode contextMode) {
		List<EvaluationCase> cases = new ArrayList<>();
		cases.add(EvaluationCase.builder("empty").build());
		cases.add(EvaluationCase.builder("fan-out data").statements(baseData()).build());
		cases.add(duplicateRows());
		cases.add(EvaluationCase.builder("sparse data")
				.statements(List.of(VF.createStatement(FuzzVocabulary.S1, FuzzVocabulary.P1, FuzzVocabulary.O1)))
				.build());
		if (contextMode == ContextMode.ALL_BINDINGS) {
			MapBindingSet incoming = new MapBindingSet();
			incoming.setBinding("v0", FuzzVocabulary.O1);
			cases.add(EvaluationCase.builder("incoming binding")
					.statements(baseData())
					.initialBindings(incoming)
					.build());
		}
		return cases;
	}

	private static List<Statement> baseData() {
		return List.of(
				VF.createStatement(FuzzVocabulary.S1, FuzzVocabulary.P1, FuzzVocabulary.O1),
				VF.createStatement(FuzzVocabulary.S1, FuzzVocabulary.P1, FuzzVocabulary.O2),
				VF.createStatement(FuzzVocabulary.S2, FuzzVocabulary.P1, FuzzVocabulary.O1),
				VF.createStatement(FuzzVocabulary.S1, FuzzVocabulary.P2, FuzzVocabulary.LITERAL_A),
				VF.createStatement(FuzzVocabulary.S2, FuzzVocabulary.P2, FuzzVocabulary.LITERAL_ONE),
				VF.createStatement(FuzzVocabulary.O1, FuzzVocabulary.P3, FuzzVocabulary.LITERAL_B_EN));
	}

	private static EvaluationCase duplicateRows() {
		// The same triple in two graphs that are BOTH part of the default dataset yields duplicate
		// solutions — the classic BAG/SET discriminator.
		SimpleDataset dataset = new SimpleDataset();
		dataset.addDefaultGraph(FuzzVocabulary.G1);
		dataset.addDefaultGraph(FuzzVocabulary.G2);
		return EvaluationCase.builder("duplicate rows via merged default graphs")
				.statements(List.of(
						VF.createStatement(FuzzVocabulary.S1, FuzzVocabulary.P1, FuzzVocabulary.O1, FuzzVocabulary.G1),
						VF.createStatement(FuzzVocabulary.S1, FuzzVocabulary.P1, FuzzVocabulary.O1, FuzzVocabulary.G2)))
				.dataset(dataset)
				.build();
	}
}
